package integration

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// TestGeneratedReadmeMatchesBehavior ties the mounted README.md (generated by
// internal/fs.generateReadme) to actual filesystem behavior, so the doc can't
// silently drift from the code again. It guards the specific bug the code review
// surfaced: the README claimed _create reads "return empty" while every _create
// node actually returns EACCES.
func TestGeneratedReadmeMatchesBehavior(t *testing.T) {
	data, err := os.ReadFile(filepath.Join(mountPoint, "README.md"))
	if err != nil {
		t.Fatalf("read README.md: %v", err)
	}
	readme := string(data)

	// The old, inaccurate claim must not reappear.
	if strings.Contains(readme, "returns empty (size 0)") {
		t.Error("README claims _create reads return empty, but _create nodes return EACCES")
	}

	// It should document the surfaces this branch added so agents learn about them.
	// "recent created updates" guards the updates trio: updates/ directories were
	// the last create surface without .error/.last, which made the README's global
	// "every writable directory has a .error" claim false there.
	// "relations, updates" pins updates' membership in the .last surface list;
	// "creates one item" pins the per-write-cycle semantics (each write to
	// _create creates another item — the old node-level buffers silently
	// swallowed the second write, so nothing documented it).
	for _, want := range []string{".last", "issue.meta", "initiative.meta", "recent/", "recent created updates", "relations, updates", "creates one item"} {
		if !strings.Contains(readme, want) {
			t.Errorf("README does not mention %q", want)
		}
	}

	// The meta split moved server fields out of the editable files. The README's
	// frontmatter templates must not document them as editable-file fields, or an
	// agent will look for/edit fields that no longer live there (the exact "the
	// generated README silently lies" failure this test exists to prevent). The
	// initiative template used to show slug:/targetDate:/owner: inside initiative.md.
	for _, leak := range []string{"slug: 77d439e363bb", "targetDate:"} {
		if strings.Contains(readme, leak) {
			t.Errorf("README documents %q as an editable-file field, but it moved to .meta", leak)
		}
	}

	// The collection meta split: every collection item {base}.md is documented
	// with a read-only {base}.meta sidecar, and comment .md files are the pure
	// body. The README's structure map must teach both.
	for _, want := range []string{"{id}.meta", "{slug}.meta", "{name}.meta", "no frontmatter", "*.meta sidecar"} {
		if !strings.Contains(readme, want) {
			t.Errorf("README does not mention %q (collection meta split)", want)
		}
	}
	// And the documented surfaces must really behave that way: a fixture doc's
	// .meta exists, reads, and rejects writes; the comment .md has no frontmatter.
	if entries, err := os.ReadDir(docsPath(testTeamKey, "TST-1")); err == nil {
		for _, e := range entries {
			if isControlFile(e.Name()) || !strings.HasSuffix(e.Name(), ".md") {
				continue
			}
			metaPath := docFilePath(testTeamKey, "TST-1", strings.TrimSuffix(e.Name(), ".md")+".meta")
			if _, err := os.ReadFile(metaPath); err != nil {
				t.Errorf("README documents doc .meta sidecars but %s is unreadable: %v", metaPath, err)
			}
			if err := os.WriteFile(metaPath, []byte("x"), 0644); err == nil {
				t.Errorf("README documents %s as read-only but it accepted a write", metaPath)
			}
			break
		}
	}
	if entries, err := os.ReadDir(commentsPath(testTeamKey, "TST-1")); err == nil {
		for _, e := range entries {
			if isControlFile(e.Name()) || !strings.HasSuffix(e.Name(), ".md") {
				continue
			}
			content, err := os.ReadFile(commentFilePath(testTeamKey, "TST-1", e.Name()))
			if err == nil && strings.HasPrefix(string(content), "---") {
				t.Errorf("README documents comment .md as frontmatter-free, but %s carries frontmatter", e.Name())
			}
			break
		}
	}

	// Spot-check the documented _create read behavior against the real node:
	// reading issues/_create must fail (write-only), matching the README.
	if _, err := os.ReadFile(issuesPath(testTeamKey) + "/_create"); err == nil {
		t.Error("issues/_create is readable, but README documents it as write-only")
	}

	// The create tail unified the failure model and closed the .last gap: the
	// README must document EAGAIN/ENOENT alongside EINVAL/EIO, and must not
	// resurrect the "attachments and relations don't report to .last" carve-out.
	for _, want := range []string{"EAGAIN", "ENOENT"} {
		if !strings.Contains(readme, want) {
			t.Errorf("README failure model does not mention %q", want)
		}
	}
	if strings.Contains(readme, "instead surface the result") {
		t.Error("README carves attachments/relations out of .last, but every create surface reports to .last now")
	}

	// Project labels (#130): the README must teach the catalog surface and the
	// assignment rules ("one child" pins group exclusivity; "retired" pins the
	// lifecycle; the reference-files line must point at the catalog).
	for _, want := range []string{"project-labels.md", "one child", "retired", "Validated project fields"} {
		if !strings.Contains(readme, want) {
			t.Errorf("README does not mention %q", want)
		}
	}
	// And the documented surface must really exist, read-only, with the
	// group marker the rules refer to.
	catalog, err := os.ReadFile(filepath.Join(mountPoint, "project-labels.md"))
	if err != nil {
		t.Fatalf("README documents project-labels.md but it is unreadable: %v", err)
	}
	if !strings.Contains(string(catalog), "group") {
		t.Error("project-labels.md does not carry the group marker the README describes")
	}
	if info, err := os.Stat(filepath.Join(mountPoint, "project-labels.md")); err == nil && info.Mode().Perm() != 0444 {
		t.Errorf("project-labels.md mode = %v, want 0444 (README: read-only)", info.Mode().Perm())
	}
}
